188→    type: getMappedTransactionType(dto.type),
189→    amount: dto.amount,
190→    currencyValue: 0,
191→    icon: dto.icon,
192→    details: {
193→      provider: '',
194→      extraInfo: '',
195→      fields: [],
196→    },
197→    status: dto.status ?? '',
